<x-filament-panels::page>
    <style>
        .domains-ui{--surface-border:#e8e2db;--text:#171717;--text-soft:#687384;--orange:#ff5b00;--orange-soft:#fff1e8;--green:#1f9a59;--green-soft:#ebfbf2;--yellow-soft:#fff5df;--red:#ff3b30;--red-soft:#ffeceb;--lavender-soft:#f5f0ff;--shadow:0 18px 40px rgba(26,25,31,.06);font-family:"Plus Jakarta Sans",sans-serif;color:var(--text)}
        .domains-ui *,.domains-ui *::before,.domains-ui *::after{box-sizing:border-box}.domains-ui button{border:0;background:none;cursor:pointer;font:inherit}.domains-ui svg{width:100%;height:100%;stroke:currentColor;stroke-width:1.8;stroke-linecap:round;stroke-linejoin:round}
        .domains-ui .domains-panel,.domains-ui .stat-card,.domains-ui .manage-button,.domains-ui .more-button,.domains-ui .filter-button,.domains-ui .new-domain-button,.domains-ui .page-button{border:1px solid var(--surface-border);background:rgba(255,255,255,.94);box-shadow:var(--shadow)}
        .domains-ui .stats-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:16px;margin-bottom:20px}.domains-ui .stat-card{display:flex;align-items:center;gap:18px;min-height:128px;padding:22px;border-radius:18px}.domains-ui .stat-icon,.domains-ui .domain-icon{display:grid;place-items:center;flex:0 0 auto}.domains-ui .stat-icon{width:48px;height:48px;border-radius:14px}.domains-ui .soft-orange{background:var(--orange-soft);color:var(--orange)}.domains-ui .soft-green{background:var(--green-soft);color:var(--green)}.domains-ui .soft-yellow{background:var(--yellow-soft);color:#f08a00}.domains-ui .soft-red{background:var(--red-soft);color:var(--red)}.domains-ui .stat-copy span{display:block;margin-bottom:8px;color:#445062}.domains-ui .stat-copy strong{display:block;margin-bottom:8px;font-size:2rem;letter-spacing:-.06em}.domains-ui .stat-copy small{color:var(--text-soft);font-size:.95rem}
        .domains-ui .domains-panel{border-radius:22px;overflow:hidden}.domains-ui .panel-toolbar{display:flex;align-items:center;justify-content:space-between;gap:16px;padding:18px 22px 0}.domains-ui .tabs{display:flex;align-items:center;gap:28px}.domains-ui .tab{position:relative;padding:10px 0 18px;color:#536071}.domains-ui .tab.is-active{color:var(--orange)}.domains-ui .tab.is-active::after{content:"";position:absolute;left:-6px;right:-6px;bottom:0;height:3px;border-radius:999px;background:var(--orange)}.domains-ui .toolbar-actions{display:flex;align-items:center;gap:14px}
        .domains-ui .filter-button,.domains-ui .new-domain-button,.domains-ui .manage-button,.domains-ui .more-button,.domains-ui .page-button{display:inline-flex;align-items:center;justify-content:center;min-height:36px;border-radius:10px}.domains-ui .filter-button,.domains-ui .new-domain-button{gap:10px;padding:0 18px;box-shadow:none}.domains-ui .filter-button{color:#475162}.domains-ui .new-domain-button{background:linear-gradient(180deg,#ff7b2f 0%,var(--orange) 100%);border-color:transparent;color:#fff}
        .domains-ui .domains-table{padding:10px 22px 0}.domains-ui .domain-grid{display:grid;grid-template-columns:minmax(280px,2.1fr) 150px 180px 130px 180px 128px;align-items:center;gap:18px}.domains-ui .domains-head{padding:16px 2px;border-top:1px solid rgba(232,226,219,.9);color:#556172;font-size:.94rem}.domains-ui .domain-row{padding:16px 2px;border-top:1px solid rgba(232,226,219,.9)}
        .domains-ui .domain-main{display:flex;align-items:center;gap:16px;min-width:0}.domains-ui .domain-icon{width:36px;height:36px;border-radius:10px;background:var(--lavender-soft);color:#566173}.domains-ui .domain-icon svg{width:18px;height:18px}.domains-ui .domain-main h2{margin:0 0 6px;font-size:.98rem;font-weight:600;letter-spacing:-.02em}.domains-ui .domain-main p,.domains-ui .domains-footer p,.domains-ui .privacy-cell,.domains-ui .renewal-cell span,.domains-ui .renewal-cell strong{margin:0}.domains-ui .domain-main p,.domains-ui .privacy-cell{color:var(--text-soft)}
        .domains-ui .status-pill{display:inline-flex;align-items:center;justify-content:center;min-height:28px;padding:0 10px;border-radius:8px;font-size:.82rem;font-weight:600;white-space:nowrap}.domains-ui .pill-green{background:#e7f8ec;color:var(--green)}.domains-ui .pill-amber{background:#fff0d8;color:#da8400}.domains-ui .pill-red{background:#ffe8e7;color:var(--red)}.domains-ui .renewal-cell strong{display:block;font-size:.95rem;font-weight:500;color:#425062}.domains-ui .renewal-cell span{display:block;margin-top:8px;color:var(--orange);font-weight:600}.domains-ui .renewal-cell.expired span,.domains-ui .renewal-cell.overdue span{color:var(--red)}
        .domains-ui .switch{position:relative;display:inline-block;width:38px;height:22px;border-radius:999px;background:#bdc4d0;vertical-align:middle}.domains-ui .switch::after{content:"";position:absolute;top:2px;left:2px;width:18px;height:18px;border-radius:50%;background:#fff;box-shadow:0 2px 8px rgba(20,23,30,.18)}.domains-ui .switch.is-on{background:linear-gradient(180deg,#ff7b2f 0%,var(--orange) 100%)}.domains-ui .switch.is-on::after{left:18px}.domains-ui .privacy-cell{display:flex;align-items:center;gap:8px}.domains-ui .shield-icon{display:inline-flex;color:currentColor}.domains-ui .protected{color:var(--green)}.domains-ui .protected span:last-child{color:#3a4d63}.domains-ui .unprotected{color:#738093}.domains-ui .action-cell{display:flex;align-items:center;gap:10px}.domains-ui .manage-button{min-width:84px;padding:0 14px;color:#212c3c;box-shadow:none}.domains-ui .more-button{width:36px;color:#4c5768;box-shadow:none}
        .domains-ui .domains-footer{display:flex;align-items:center;justify-content:space-between;gap:16px;padding:18px 22px 14px}.domains-ui .pagination{display:flex;align-items:center;gap:10px}.domains-ui .page-button{min-width:34px;padding:0 12px;color:#516071;box-shadow:none}.domains-ui .page-button.is-active{background:linear-gradient(180deg,#ff7b2f 0%,var(--orange) 100%);border-color:transparent;color:#fff}.domains-ui .icon-button{width:34px;padding:0}
        @media (max-width:1380px){.domains-ui .domain-grid{grid-template-columns:minmax(220px,2fr) 130px 170px 120px 160px 120px}}
        @media (max-width:1180px){.domains-ui .stats-grid{grid-template-columns:repeat(2,minmax(0,1fr))}.domains-ui .panel-toolbar{flex-direction:column;align-items:flex-start}.domains-ui .domain-grid,.domains-ui .domains-head{grid-template-columns:1fr}.domains-ui .domains-head{display:none}.domains-ui .domain-row{gap:10px}}
        @media (max-width:760px){.domains-ui .stats-grid{grid-template-columns:1fr}.domains-ui .tabs{width:100%;overflow-x:auto;padding-bottom:4px}.domains-ui .toolbar-actions,.domains-ui .domains-footer{width:100%;flex-direction:column;align-items:flex-start}}
